import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const D=JSON.parse('{"title":"eDDA电子授权扣账","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/edda.md","filePath":"zh-CN/deposit/edda.md"}'),o={name:"deposit/edda.md"};function l(i,t,n,h,p,s){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="edda电子授权扣账" tabindex="-1">eDDA电子授权扣账 <a class="header-anchor" href="#edda电子授权扣账" aria-label="Permalink to &quot;eDDA电子授权扣账&quot;">​</a></h1><p>eDDA 快捷入金是香港金管局基于 FPS 转数快系统推出的授权扣款服务，授权后可直接从长桥 App 发起入金，资金从绑定银行账户自动扣除，无需上传转账凭证。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）</td></tr><tr><td>到账时间</td><td>港股交易日 5 分钟内；其他时段下一港股交易日 09:40 前（港股休市日顺延）</td></tr><tr><td>手续费</td><td>免费；账户余额不足时部分银行（如汇丰）可能扣费，转账前请确保账户余额充足</td></tr></tbody></table><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><h3 id="第一步-完成-edda-授权" tabindex="-1">第一步：完成 eDDA 授权 <a class="header-anchor" href="#第一步-完成-edda-授权" aria-label="Permalink to &quot;第一步：完成 eDDA 授权&quot;">​</a></h3><p><strong>方式一：在长桥 App 内发起（推荐）</strong></p><ol><li>打开长桥 App，进入<strong>资产 → 存入资金 → 存入港元 → 香港银行卡</strong></li><li>选择银行卡 → <strong>eDDA 入金</strong> → 申请授权（有 eDDA 标签的表示支持）</li><li>确认银行授权信息（卡号、姓名），点击「确认授权」</li><li>等待授权结果，成功后收到推送消息和邮件通知</li></ol><blockquote><p>开户证件类型、姓名排序必须与银行开户时一致，否则授权失败。大部分银行约 5 分钟出结果，个别银行需 2–14 个工作日。</p></blockquote><p><strong>方式二：在银行端发起</strong></p><p>花旗银行、东亚银行、招商银行需在银行网页端发起 eDDA 授权，授权成功后再在长桥 App 发起入金。在 App 内多次授权失败时也可尝试此方式。</p><p>各银行详细步骤请在长桥 App 入金页面查看（汇丰、恒生、中银香港、工银亚洲、招商银行等）。</p><h3 id="第二步-发起入金" tabindex="-1">第二步：发起入金 <a class="header-anchor" href="#第二步-发起入金" aria-label="Permalink to &quot;第二步：发起入金&quot;">​</a></h3><p>授权成功后，在长桥 App 的 eDDA 入金页面点击「立即入金」，输入金额即可。无需上传入金凭证。</p><h2 id="解除授权与删除银行卡" tabindex="-1">解除授权与删除银行卡 <a class="header-anchor" href="#解除授权与删除银行卡" aria-label="Permalink to &quot;解除授权与删除银行卡&quot;">​</a></h2><ul><li>解除 eDDA 授权需在对应银行网银端操作，App 端不支持解除</li><li>需先解除 eDDA 授权，才能在 App 删除该银行卡</li><li>如在长桥侧解绑后再次绑定出现「重复授权」报错，通常是银行端未成功解除，需联系银行处理</li></ul><h2 id="常见授权失败原因" tabindex="-1">常见授权失败原因 <a class="header-anchor" href="#常见授权失败原因" aria-label="Permalink to &quot;常见授权失败原因&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误信息</th><th>原因</th></tr></thead><tbody><tr><td>Debtor account name / ID not matched</td><td>证件类型或姓名格式问题，字母需大写</td></tr><tr><td>Invalid debtor account number</td><td>账号错误、加了银行代码、或使用了分币种账号</td></tr><tr><td>Mandate identification already exists</td><td>银行端与长桥 App 端同时发起授权</td></tr><tr><td>Debtor account not found</td><td>账号有误</td></tr><tr><td>Rejected by Other bank</td><td>银行卡账户类型问题（如绑定了美元账户类型）</td></tr><tr><td>Invalid Payer ID</td><td>银行卡证件信息与开户信息不一致</td></tr></tbody></table><p>如排查完所有原因仍无法授权，可联系银行重置 eDDA 后再次尝试。华侨银行一般需 2 个工作日处理。</p><h2 id="同名账户要求与出金限制" tabindex="-1">同名账户要求与出金限制 <a class="header-anchor" href="#同名账户要求与出金限制" aria-label="Permalink to &quot;同名账户要求与出金限制&quot;">​</a></h2><ul><li>转账银行账户名必须与长桥证券账户名同名，不可使用他人账户转账</li><li>银行通知「已汇出」不代表长桥已收款，资金到达后需结算与审批</li><li>香港节假日期间不处理汇款业务，请预留时间</li><li>eDDA 不支持出金</li></ul>',20)])])}const b=a(o,[["render",l]]);export{D as __pageData,b as default};
